/**
 * Migrate a single `telemetry-event` resource to the current schema version.

**Path Parameters:**
- `resource_id`: The unique identifier of the resource to migrate

**Query Parameters:**
- `write_back` (optional, default=true): Whether to write migrated data back to storage
- `revision_id` (optional): A specific revision to migrate.
  When omitted the current revision is migrated.

**Response:**
- Returns migration progress for the single resource:
  - `resource_id`: The resource that was migrated
  - `status`: Migration status (success/failed/skipped)
  - `message`: Success message or additional info
  - `error`: Error message if migration failed

**Use Cases:**
- Migrate specific resource after schema update
- Migrate an older revision so it can be switched to
- Fix individual resource migration issues
- Test migration on single resource
- Manual resource upgrade

**Examples:**
- `POST /telemetry-event/migrate/single/123` - Migrate resource 123
- `POST /telemetry-event/migrate/single/123?revision_id=123:1` - Migrate specific revision
- `POST /telemetry-event/migrate/single/123?write_back=false` - Test migrate resource 123

**Error Responses:**
- `404`: Resource not found
- `400`: Migration failed
 * @summary Migrate Single telemetry-event Resource
 */
export const MigrateSingleResourceTelemetryEventMigrateSingleResourceIdPostParams = zod.object({
  "resource_id": zod.string()
})

export const migrateSingleResourceTelemetryEventMigrateSingleResourceIdPostQueryWriteBackDefault = true;

export const MigrateSingleResourceTelemetryEventMigrateSingleResourceIdPostQueryParams = zod.object({
  "write_back": zod.boolean().default(migrateSingleResourceTelemetryEventMigrateSingleResourceIdPostQueryWriteBackDefault).describe('Whether to write migrated data back to storage'),
  "revision_id": zod.union([zod.string(),zod.null()]).optional().describe('Specific revision ID to migrate. When omitted the current revision is migrated.')
})

export const migrateSingleResourceTelemetryEventMigrateSingleResourceIdPostResponseMessageDefault = null;
export const migrateSingleResourceTelemetryEventMigrateSingleResourceIdPostResponseErrorDefault = null;

